import com.pinterest.ktlint.ruleset.standard.rules.ImportOrderingRule
import com.pinterest.ktlint.ruleset.standard.rules.ImportOrderingRule.Companion.IJ_KOTLIN_IMPORTS_LAYOUT_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class ImportOrderingRuleBlankLineBugTest {
    private val importOrderingRuleAssertThat = assertThatRule { ImportOrderingRule() }

    @Test
    fun `Given imports layout with multiple blank lines and no imports matching first groups then do not add extra blank lines before first import`() {
        // This test reproduces the bug from the issue:
        // ij_kotlin_imports_layout = *, |, javax.**, java.**, |, kotlinx.**, kotlin.**
        // With only java.** imports, the two | at positions before any matching import
        // should not generate extra blank lines
        val code =
            """
            import java.nio.file.Files
            import java.nio.file.Paths
            import java.util.Objects

            object TestData {
                fun loadString(dataset: String): String {
                    val path = Paths.get(Objects.requireNonNull(TestData::class.java.getResource(dataset)).toURI())
                    return String(Files.readAllBytes(path))
                }
            }
            """.trimIndent()

        importOrderingRuleAssertThat(code)
            .withEditorConfigOverride(IJ_KOTLIN_IMPORTS_LAYOUT_PROPERTY to "*,|,javax.**,java.**,|,kotlinx.**,kotlin.**")
            .hasNoLintViolations()
    }

    @Test
    fun `Given imports layout with blank line before first matching import then do not add blank line before first import`() {
        // Simpler case: pattern starts with | before any matching import
        val code =
            """
            import java.util.List
            import kotlin.concurrent.Thread
            """.trimIndent()

        importOrderingRuleAssertThat(code)
            .withEditorConfigOverride(IJ_KOTLIN_IMPORTS_LAYOUT_PROPERTY to "|,java.**,|,kotlin.**")
            .hasNoLintViolations()
    }

    @Test
    fun `Given imports layout with multiple consecutive blank lines at start then do not add blank lines before first import`() {
        val code =
            """
            import java.util.List
            """.trimIndent()

        importOrderingRuleAssertThat(code)
            .withEditorConfigOverride(IJ_KOTLIN_IMPORTS_LAYOUT_PROPERTY to "|,|,|,java.**")
            .hasNoLintViolations()
    }
}
"}

